import { Component, OnDestroy, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormArray, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Subject, startWith, takeUntil } from 'rxjs';
import { Quote, QuoteRemiseType } from '../../models/quote';
import { InvoiceLine } from '../../models/invoice-line';
import { QuoteCalcService, QuoteTotals } from '../../services/quote-calc.service';
import { QuoteStoreService } from '../../services/quote-store.service';

const TVA_RATE = 19;

@Component({
  selector: 'app-quote-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule],
  templateUrl: './quote-form.component.html',
  styleUrls: ['./quote-form.component.css']
})
export class QuoteFormComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  form = this.fb.group({
    numero: ['', Validators.required],
    date: ['', Validators.required],
    client: this.fb.group({
      nom: ['', Validators.required],
      adresse: ['', Validators.required],
      tel: [''],
      mf: [''],
      email: ['']
    }),
    lignes: this.fb.array([]),
    remiseType: ['montant' as QuoteRemiseType],
    remiseValue: [0],
    notes: [''],
    conditions: ['']
  });

  totals: QuoteTotals = {
    totalHT: 0,
    remise: 0,
    totalHTApresRemise: 0,
    fodec: 0,
    totalHorsTVA: 0,
    tva: 0,
    totalTTC: 0
  };

  isEdit = false;
  numeroConflict = false;

  private currentId: string | null = null;

  constructor(
    private fb: FormBuilder,
    private store: QuoteStoreService,
    public calc: QuoteCalcService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  get lignes(): FormArray {
    return this.form.get('lignes') as FormArray;
  }

  async ngOnInit(): Promise<void> {
    await this.store.load();

    const id = this.route.snapshot.paramMap.get('id');

    if (id) {
      this.isEdit = true;
      const quote = await this.store.getById(id);
      if (!quote) {
        this.router.navigate(['/quotes']);
        return;
      }

      this.currentId = quote.id;

      this.form.patchValue({
        numero: quote.numero,
        date: quote.date,
        client: quote.client,
        remiseType: quote.remiseType ?? 'montant',
        remiseValue: quote.remiseValue ?? 0,
        notes: quote.notes ?? '',
        conditions: quote.conditions ?? ''
      });

      this.setLines(quote.lignes ?? []);
    } else {
      this.isEdit = false;
      this.currentId = this.ensureCurrentId();

      const numero = await this.store.getNextQuoteNumber();
      this.form.patchValue({
        numero,
        date: new Date().toISOString().slice(0, 10),
        remiseType: 'montant',
        remiseValue: 0
      });

      this.addLine();
    }

    this.form.valueChanges
      .pipe(startWith(this.form.getRawValue()), takeUntil(this.destroy$))
      .subscribe(() => this.updateTotals());

    this.updateTotals();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  addLine(): void {
    this.lignes.push(this.createLine());
  }

  removeLine(index: number): void {
    if (this.lignes.length <= 1) return;
    this.lignes.removeAt(index);
  }

  lineHT(index: number): number {
    const line = this.normalizeLine(this.lignes.at(index).value as InvoiceLine);
    return this.calc.lineHT(line);
  }

  async save(goToPreview: boolean): Promise<void> {
    this.numeroConflict = false;

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const quote = this.buildQuote();

    const unique = await this.store.isNumeroUnique(quote.numero, quote.id);
    if (!unique) {
      this.numeroConflict = true;
      return;
    }

    await this.store.save(quote);

    if (goToPreview) {
      this.router.navigate(['/quotes', quote.id, 'preview']);
    } else {
      this.router.navigate(['/quotes']);
    }
  }

  cancel(): void {
    this.router.navigate(['/quotes']);
  }

  private updateTotals(): void {
    const quote = this.buildQuote();
    this.totals = this.calc.totals(quote);
  }

  private setLines(lines: InvoiceLine[]): void {
    this.lignes.clear();
    lines.forEach((line) => this.lignes.push(this.createLine(line)));
    if (lines.length === 0) this.addLine();
  }

  private createLine(line?: InvoiceLine): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [line?.id ?? this.createId()],
      designation: [line?.designation ?? '', Validators.required],
      unite: [line?.unite ?? '', Validators.required],
      quantite: [line?.quantite ?? 0, [Validators.required, Validators.min(0)]],
      prixUnitaire: [line?.prixUnitaire ?? 0, [Validators.required, Validators.min(0)]],
      tvaRate: [TVA_RATE]
    });
  }

  private buildQuote(): Quote {
    const raw = this.form.getRawValue();

    return {
      id: this.ensureCurrentId(),
      numero: (raw.numero ?? '').trim(),
      date: (raw.date ?? new Date().toISOString().slice(0, 10)).trim(),
      client: {
        nom: raw.client?.nom ?? '',
        adresse: raw.client?.adresse ?? '',
        tel: raw.client?.tel ?? '',
        mf: raw.client?.mf ?? '',
        email: raw.client?.email ?? ''
      },
      lignes: ((raw.lignes ?? []) as InvoiceLine[]).map((l) => this.normalizeLine(l)),
      remiseType: raw.remiseType ?? 'montant',
      remiseValue: Number(raw.remiseValue) || 0,
      notes: raw.notes ?? '',
      conditions: raw.conditions ?? ''
    };
  }

  private normalizeLine(line: InvoiceLine): InvoiceLine {
    return {
      ...line,
      quantite: Number(line.quantite) || 0,
      prixUnitaire: Number(line.prixUnitaire) || 0,
      tvaRate: TVA_RATE
    };
  }

  private ensureCurrentId(): string {
    if (!this.currentId) {
      this.currentId = this.createId();
    }

    return this.currentId;
  }

  private createId(): string {
    return globalThis.crypto?.randomUUID?.() ??
      `quote_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  }
}
<div class="preview-toolbar no-print">
  <button class="btn ghost" routerLink="/quotes">Retour</button>

  <div class="toolbar-actions">
    <a class="btn outline" *ngIf="quote?.id" [routerLink]="['/quotes', quote.id, 'edit']">Modifier</a>
    <button class="btn primary" (click)="print()" [disabled]="!quote">Imprimer</button>
    <button class="btn ghost" *ngIf="electron.isElectron" (click)="exportPdf()" [disabled]="!quote">
      Exporter PDF
    </button>
  </div>
</div>

<div class="invoice-page" *ngIf="quote as q">
  <!-- ======= TOP HEADER (FR | LOGO | AR) ======= -->
  <header class="top-header">
    <div class="company-fr">
      <div class="line1">SOCIETE PRATIQUES ALUMINIUM</div>
      <div>59, Av. de l’Indépendance - Cité Ettadhamen</div>
      <div>2041 ARIANA</div>
    </div>

    <div class="top-logo">
      <img
        *ngIf="logoAvailable"
        src="assets/logospa.png"
        alt="SPA logo"
        (error)="logoAvailable = false"
      />
      <div *ngIf="!logoAvailable" class="logo-fallback">SPA</div>
    </div>

    <div class="company-ar" dir="rtl" lang="ar">
      <div class="line1">شركة تطبيقات الألومنيوم</div>
      <div>59، شارع الاستقلال - حي التضامن</div>
      <div>2041 أريانة</div>
    </div>
  </header>

  <!-- ======= CLIENT CENTER + DATE RIGHT ======= -->
  <section class="client-row">
    <div class="client-center">
      <div class="client-name">{{ q.client.nom }}</div>

      <div class="client-sub" *ngIf="q.client.adresse">{{ q.client.adresse }}</div>

      <div class="client-sub" *ngIf="q.client.mf">
        CODE T.V.A : {{ q.client.mf }}
      </div>
    </div>

    <div class="date-right">
      <div class="muted">Tunis, le</div>
      <div class="date-strong">{{ q.date | date:'dd/MM/yyyy' }}</div>
    </div>
  </section>

  <!-- ======= TITLE ======= -->
  <div class="invoice-title">
    DEVIS N° <span class="mono">{{ q.numero }}</span>
  </div>

  <div class="order-line">
    Bon de Commande N° <span class="muted">—</span>
  </div>

  <!-- ======= TABLE ======= -->
  <table class="invoice-table">
    <thead>
      <tr>
        <th class="col-ord">ORD</th>
        <th>DESIGNATIONS</th>
        <th class="col-u">U</th>
        <th class="col-q">QUANT</th>
        <th class="col-pu">P.UNIT</th>
        <th class="col-pt">P.TOTAL</th>
      </tr>
    </thead>

    <tbody>
      <tr *ngFor="let line of q.lignes; let i = index">
        <td class="center">{{ i + 1 }}</td>
        <td>{{ line.designation }}</td>
        <td class="center">{{ line.unite }}</td>
        <td class="center">{{ line.quantite | number:'1.0-3' }}</td>
        <td class="num">{{ line.prixUnitaire | number:'1.3-3' }}</td>
        <td class="num">{{ lineHT(line) | number:'1.3-3' }}</td>
      </tr>
    </tbody>
  </table>

  <!-- ======= TOTALS RIGHT BOX (DEVIS: NO TVA / NO TTC) ======= -->
  <div class="totals-area">
    <table class="totals">
      <tbody>
        <tr>
          <td>TOTAL Hors taxes</td>
          <td class="num">{{ totals.baseHT | number:'1.3-3' }}</td>
        </tr>

        <tr *ngIf="totals.remise > 0">
          <td>Remise</td>
          <td class="num">- {{ totals.remise | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Fodec (1%)</td>
          <td class="num">{{ totals.fodec | number:'1.3-3' }}</td>
        </tr>

        <tr class="grand">
          <td>TOTAL Hors T.V.A</td>
          <td class="num">{{ totals.totalHorsTVA | number:'1.3-3' }}</td>
        </tr>
      </tbody>
    </table>
  </div>

  <!-- ======= TOTAL IN WORDS (based on Hors TVA) ======= -->
  <div class="ttc-words">
    Arrêté le présent devis à la somme de :
    <strong>{{ totalText }}</strong>
  </div>

  <!-- ======= FOOTER ======= -->
  <footer class="invoice-footer">
    R.C. : B035 145 2004 - M.F. : 89 83 00 W/A/M/000 - RIB : 25079 0000000 213 555 60 zitouna Mutuelle ville<br />
    Tél. : 71 515 491 - Fax : 70 661 034 - E-mail : saadani.karim@planet.tn
  </footer>
</div>

<div class="empty card" *ngIf="!quote">
  Devis introuvable.
</div>
